var EnhancedEcommerce={AddImpression(e,t,i){gtag("event","view_item",{items:[{id:e,name:t,variant:i}]})},AddProduct(e,t,i,a,r,n){gtag("event","add_to_cart",{items:[{id:e,name:t,category:a,brand:r,variant:i,price:n,quantity:arguments.length>6&&void 0!==arguments[6]?arguments[6]:1}]})},Purchase(e,t,i,a){gtag("event","purchase",{transaction_id:e,affiliation:"Webapp Order",value:t,currency:"VND",shipping:i,items:a})},PurchaseTest(e,t,i,a){dataLayer("event","purchase",{transaction_id:e,affiliation:"Webapp Order test",value:t,currency:"VND",shipping:i,items:a})},BeginCheckout(e,t){gtag("event","begin_checkout",{currency:"VND",value:e,items:t})},ViewItemList(e,t,i){gtag("event","view_item_list",{item_list_id:e,item_list_name:t,items:i})},ViewCart(e,t){gtag("event","view_cart",{currency:"VND",value:e,items:t})},SetUserProperties(e,t,i){gtag("set",{user_id:e}),gtag("set","user_properties",{user_type:t,user_name:i})}};